effect.shader:
void main() {
    float rad = angle * 0.0174533;
    mat2 rot = mat2(cos(rad),-sin(rad),sin(rad),cos(rad));
    mat2 invrot = mat2(cos(-rad),-sin(-rad),sin(-rad),cos(-rad));
    vec2 sampleCoord = ((((acLayerNorm - 0.5) * rot) * vec2((1.0/scale), 1.0)) * invrot) + 0.5;
    sampleCoord = (vec4(sampleCoord,0.0,1.0) * acLayerToScreen).xy;
    if( contentOnly ) {
        vec4 texColor = texture2DCv(inputImg.texture,acScreenNorm);
        vec4 newColor = texture2DCv(inputImg.texture,sampleCoord) * texColor.a;
        gl_FragColor = newColor + (texColor * (1.0-newColor.a));
    } else {
        gl_FragColor = texture2DCv(inputImg.texture,sampleCoord);
    }
}
